const data = $input.first().json;
if (data.error || data.loggedOut) return [];
const convList = (data.items || []).slice(0, 5);
if (!convList.length) return [];
return convList.map(function(i){ return { json: i }; });

try {
const thread = $input.item.json;
const listItem = $('🔍 Nur ungelesene').item.json;

const messages = thread.messages || [];
if (!messages.length) return [];

// Letztes Message muss eingehend sein – sonst bereits beantwortet
const lastMsg = messages[messages.length - 1];
if (!lastMsg || lastMsg.own) return [];

// Schon ein KI-Draft → überspringen
if (thread.draft) return [];

// Kompliment → automatisch als gelesen markieren, kein Draft nötig
const isKompliment = messages.some(m => m.isKompliment);
if (isKompliment) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://f3-cookie-crawler:3000/messages/mark-read',
      headers: { 'Content-Type': 'application/json' },
      body: { convId: listItem.id, convUrl: listItem.url },
      json: true, timeout: 20000
    });
    console.log('Kompliment auto-gelesen:', listItem.name);
  } catch(e) { console.log('mark-read Fehler:', e.message); }
  return []; // kein Draft für Komplimente
}

let contextHint = '';
const wartelisteMsg = messages.find(m => m.own && /warteliste/i.test(m.text || ''));
const wartelisteIndex = wartelisteMsg ? messages.lastIndexOf(wartelisteMsg) : -1;
const wartelisteRecent = wartelisteIndex >= 0 && wartelisteIndex >= messages.length - 4;
if (wartelisteRecent) {
  const hasPhoto = messages.some(m => !m.own && (m.isImage || /foto/i.test(m.text || '')));
  if (!hasPhoto) {
    const autoText = 'Hey ' + listItem.name + '! ☺️ Danke für deine Anmeldung!\n\nUnser Ladies-Voting findet 1x pro Woche (donnerstags) statt. Damit wir dich beim nächsten Voting berücksichtigen können, schick uns bitte noch ein Foto von dir hier in den Chat. Wir melden uns dann nach dem Voting bei dir! 🙏';
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://f3-cookie-crawler:3000/messages/send',
        headers: { 'Content-Type': 'application/json' },
        body: { name: listItem.name, url: listItem.url, text: autoText },
        json: true, timeout: 60000
      });
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://f3-cookie-crawler:3000/api/auto-reply-log',
        headers: { 'Content-Type': 'application/json' },
        body: { name: listItem.name, type: 'warteliste_no_photo', replyText: autoText, convId: listItem.id, convUrl: listItem.url },
        json: true, timeout: 5000
      });
      console.log('Warteliste Auto-Reply gesendet:', listItem.name);
    } catch(e) { console.log('Auto-Reply Fehler:', e.message); }
    return [];
  }
  if (lastMsg.isImage) {
    contextHint = 'FOTO_EINGEGANGEN: Person hat gerade ein Foto für das Voting geschickt. Kurze freundliche Dankesantwort + bestätige Donnerstags-Voting-Teilnahme.';
  }
}

const recent = messages.slice(-20);
const history = recent.map(m => {
  const who = m.own ? 'Tobi (ich)' : listItem.name;
  const txt = m.isImage ? '[Foto]' : (m.text || '');
  return who + ': ' + txt.substring(0, 300);
}).join('\n');

const wartelisteEvents = messages
  .filter(m => m.own && /warteliste/i.test(m.text || ''))
  .map(m => { const ma = m.text.match(/für\s+(.+?)\s+am\s+/i); return ma ? ma[1].trim() : null; })
  .filter(Boolean);
const wartelisteStatus = wartelisteEvents.length
  ? 'BEREITS AUF WARTELISTE: ' + wartelisteEvents.join(', ')
  : '';

let eventKnowledge = '';
try {
  const kb = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://f3-cookie-crawler:3000/status/event-knowledge',
    timeout: 5000
  });
  const entries = (kb && kb.data && kb.data.knowledge) || (kb && kb.knowledge) || [];
  if (entries.length) {
    eventKnowledge = entries.map(e =>
      '=== ' + e.name + ' (' + e.datum + ') ===\n' +
      'Link: ' + e.link + '\n' +
      'Preise: ' + e.preise + '\n' +
      'Dresscode: ' + e.dresscode + '\n' +
      (e.uhrzeit ? 'Einlass/Beginn: ' + e.uhrzeit + ' Uhr\n' : '') +
      (e.kapazitaet ? 'Kapazität: ' + e.kapazitaet + ' Personen\n' : '') +
      'Info: ' + e.beschreibung.substring(0, 400)
    ).join('\n\n');
  }
} catch(e) {
  console.log('Knowledge Base nicht verfügbar:', e.message);
}

let profileKnowledge = '';
try {
  const pk = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://f3-cookie-crawler:3000/status/profile-knowledge',
    timeout: 5000
  });
  const pages = (pk && pk.data && pk.data.pages) || (pk && pk.pages) || [];
  if (pages.length) {
    profileKnowledge = pages
      .filter(p => p.text && p.text.length > 50)
      .map(p => '=== ' + (p.title || p.url) + ' ===\n' + p.text.substring(0, 600))
      .join('\n\n');
  }
} catch(e) {
  console.log('Profile-Knowledge nicht verfügbar:', e.message);
}

// isFirstMessage + senderName für Signatur-Logik
const isFirstMessage = !messages.some(function(m){ return m.own; });
const senderName = 'Tobi';

// promptText komplett in JS bauen (keine n8n-Template-Syntax {{ }})
const promptParts = [
  'Absender: ' + listItem.name + (listItem.gender ? ' (' + listItem.gender + ')' : ''),
  ''
];
if (wartelisteStatus) promptParts.push('WICHTIGER KONTEXT - ' + wartelisteStatus);
if (contextHint) promptParts.push('HINWEIS: ' + contextHint);
promptParts.push('', 'Gesprächsverlauf (neueste Nachricht zuletzt):', history, '', 'Letzte Nachricht:', lastMsg.text || (lastMsg.isImage ? '[Foto]' : ''), '', 'Gib NUR den fertigen Antworttext aus. Kein Betreff, keine Erklärung.');
const promptText = promptParts.join('\n');

return [{ json: {
  name: listItem.name,
  lastMessage: lastMsg.text || (lastMsg.isImage ? '[Foto]' : ''),
  history,
  gender: listItem.gender || null,
  eventKnowledge,
  profileKnowledge,
  wartelisteStatus,
  contextHint,
  isFirstMessage,
  senderName,
  promptText
}}];
} catch(e) {
  console.error('Kontext aufbereiten error:', e.message);
  return [];
}

